import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";

export default function Profile() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [showComments, setShowComments] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  
  // حالة التعليقات
  const [comments, setComments] = useState([
    { id: 1, author: "Sophie Martin", text: "Excellente prestation ! Je recommande vivement 👍", rating: 5, date: "2024-03-15" },
    { id: 2, author: "Thomas Dubois", text: "Service rapide et professionnel. Très satisfait.", rating: 4, date: "2024-03-10" },
    { id: 3, author: "Marie Lambert", text: "Super expérience, à refaire ! 🌟", rating: 5, date: "2024-03-05" }
  ]);
  
  const [newComment, setNewComment] = useState({ author: "", text: "", rating: 5 });
  
  const [workerInfo, setWorkerInfo] = useState({
    name: "Jenna Stones",
    role: "Développeuse Full Stack",
    experience: "5 ans d'expérience",
    skills: ["React.js", "Node.js", "Tailwind CSS", "Figma", "TypeScript", "MongoDB"],
    bio: "Développeuse passionnée avec une expertise en création d'applications web modernes. J'aime relever des défis techniques et créer des expériences utilisateur exceptionnelles.",
    email: "jenna.stones@example.com",
    phone: "+33 6 12 34 56 78",
    location: "Paris, France",
    languages: ["Français", "Anglais", "Espagnol"]
  });
  
  const [workHistory, setWorkHistory] = useState([
    { place: "Le Café Paris", role: "Développeuse Frontend", duration: "2023 - Présent", rating: 5, review: "Excellente développeuse, très professionnelle !" },
    { place: "Tech Startup Lyon", role: "Développeuse Web", duration: "2021 - 2023", rating: 4, review: "Bon travail, équipe sympathique." },
    { place: "Agence Digital", role: "Stagiaire Développeuse", duration: "2020 - 2021", rating: 4.5, review: "Apprentissage rapide, très motivée." }
  ]);
  
  const [currentRating, setCurrentRating] = useState(0);
  const [managerComment, setManagerComment] = useState("");
  
  const availablePlaces = [
    { id: 1, name: "Le Café Paris", location: "Paris", type: "Café", icon: "☕" },
    { id: 2, name: "Restaurant La Mer", location: "Marseille", type: "Restaurant", icon: "🍽️" },
    { id: 3, name: "Tech Hub Lyon", location: "Lyon", type: "Bureau", icon: "💻" },
    { id: 4, name: "Startup Factory", location: "Toulouse", type: "Coworking", icon: "🚀" }
  ];
  
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [showPlaceSelector, setShowPlaceSelector] = useState(false);
  
  // دالة لإضافة تعليق جديد
  const addComment = () => {
    if (newComment.author && newComment.text) {
      const comment = {
        id: comments.length + 1,
        author: newComment.author,
        text: newComment.text,
        rating: newComment.rating,
        date: new Date().toLocaleDateString('fr-FR')
      };
      setComments([comment, ...comments]);
      setNewComment({ author: "", text: "", rating: 5 });
      setShowComments(false);
      alert("✅ Merci pour votre commentaire !");
    } else {
      alert("⚠️ Veuillez entrer votre nom et votre commentaire");
    }
  };
  
  const addManagerReview = () => {
    if (currentRating > 0 && managerComment) {
      const newHistory = {
        place: currentWorkPlace,
        role: workerInfo.role,
        duration: new Date().toLocaleDateString('fr-FR'),
        rating: currentRating,
        review: managerComment
      };
      setWorkHistory([newHistory, ...workHistory]);
      setCurrentRating(0);
      setManagerComment("");
      alert("✅ Évaluation ajoutée avec succès !");
    } else {
      alert("⚠️ Veuillez sélectionner une note et ajouter un commentaire");
    }
  };
  
  const changeWorkPlace = (place) => {
    setCurrentWorkPlace(place.name);
    setSelectedPlace(place);
    setShowPlaceSelector(false);
    setWorkerStatus("working");
    alert(`✅ Lieu de travail changé : ${place.name}`);
  };
  
  const deactivateWorker = () => {
    setWorkerStatus("free");
    setCurrentWorkPlace("");
    alert("⚠️ Statut changé : En recherche d'emploi");
  };
  
  const activateWorker = () => {
    setShowPlaceSelector(true);
  };

  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .cards-container {
      display: flex;
      gap: 30px;
      justify-content: center;
      margin-top: 40px;
      flex-wrap: wrap;
    }
    
    .cv-card {
      flex: 1;
      min-width: 280px;
      background: rgba(255,255,255,0.1);
      backdrop-filter: blur(15px);
      border-radius: 25px;
      padding: 30px 20px;
      cursor: pointer;
      transition: all 0.3s ease;
      border: 1px solid rgba(255,255,255,0.3);
      text-align: center;
    }
    
    .cv-card:first-child {
      background: linear-gradient(135deg, rgba(255,107,107,0.25), rgba(245,87,108,0.2));
      border-color: #ff6b6b;
    }
    
    .cv-card:first-child:hover {
      background: linear-gradient(135deg, rgba(255,107,107,0.4), rgba(245,87,108,0.3));
      border-color: #ff6b6b;
      transform: translateY(-10px);
    }
    
    .cv-card:last-child {
      background: linear-gradient(135deg, rgba(78,205,196,0.25), rgba(69,183,209,0.2));
      border-color: #4ecdc4;
    }
    
    .cv-card:last-child:hover {
      background: linear-gradient(135deg, rgba(78,205,196,0.4), rgba(69,183,209,0.3));
      border-color: #4ecdc4;
      transform: translateY(-10px);
    }
    
    /* Section commentaires sur la droite */
    .comments-sidebar {
      position: fixed;
      right: 20px;
      top: 50%;
      transform: translateY(-50%);
      width: 320px;
      background: rgba(0,0,0,0.6);
      backdrop-filter: blur(15px);
      border-radius: 25px;
      padding: 20px;
      border: 1px solid rgba(255,255,255,0.2);
      z-index: 20;
      max-height: 70vh;
      overflow-y: auto;
    }
    
    .comments-sidebar::-webkit-scrollbar {
      width: 4px;
    }
    
    .comments-sidebar::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    
    .comments-sidebar::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    .comment-item {
      background: rgba(255,255,255,0.1);
      border-radius: 15px;
      padding: 12px;
      margin-bottom: 12px;
      transition: all 0.3s;
    }
    
    .comment-item:hover {
      background: rgba(255,255,255,0.15);
      transform: translateX(-5px);
    }
    
    .comment-author {
      font-weight: bold;
      color: #ff6b6b;
      font-size: 14px;
    }
    
    .comment-text {
      color: #ddd;
      font-size: 13px;
      margin: 8px 0;
    }
    
    .comment-rating {
      color: #ffc107;
      font-size: 12px;
    }
    
    .comment-date {
      color: #888;
      font-size: 10px;
      text-align: right;
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 8px 16px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      width: 100%;
      margin-top: 10px;
    }
    
    .btn-comment:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 15px rgba(255,107,107,0.4);
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.85);
      backdrop-filter: blur(10px);
      z-index: 100;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 500px;
      width: 90%;
      max-height: 80vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      box-shadow: 0 0 40px rgba(34,197,94,0.3);
      animation: slideUp 0.4s ease;
    }
    
    @keyframes slideUp {
      from { transform: translateY(50px); opacity: 0; }
      to { transform: translateY(0); opacity: 1; }
    }
    
    .modal-content::-webkit-scrollbar {
      width: 6px;
    }
    
    .modal-content::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    
    .modal-content::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    .stars {
      display: flex;
      gap: 8px;
      justify-content: center;
      margin: 15px 0;
    }
    
    .rating-input {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin: 10px 0;
    }
    
    .rating-star {
      font-size: 30px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star:hover {
      transform: scale(1.2);
    }
    
    .rating-star.active {
      color: #ffc107;
      text-shadow: 0 0 10px #ffc107;
    }
    
    .work-history-item {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
      transition: all 0.3s;
      border-left: 4px solid #22c55e;
    }
    
    .work-history-item:hover {
      background: rgba(255,255,255,0.12);
      transform: translateX(5px);
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
    }
    
    .status-working {
      background: #22c55e;
      color: white;
    }
    
    .status-free {
      background: #ef4444;
      color: white;
    }
    
    .place-selector {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 15px;
      margin-top: 20px;
    }
    
    .place-option {
      background: rgba(34,197,94,0.15);
      border: 1px solid #22c55e;
      border-radius: 15px;
      padding: 15px;
      cursor: pointer;
      transition: all 0.3s;
      text-align: center;
    }
    
    .place-option:hover {
      background: rgba(34,197,94,0.3);
      transform: scale(1.02);
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: #22c55e20;
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid #22c55e40;
    }
    
    .btn-primary {
      background: #22c55e;
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .btn-primary:hover {
      background: #15803d;
      transform: scale(1.02);
    }
    
    .btn-danger {
      background: #ef4444;
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .btn-danger:hover {
      background: #b91c1c;
      transform: scale(1.02);
    }
    
    @media (max-width: 1200px) {
      .comments-sidebar {
        position: relative;
        right: auto;
        top: auto;
        transform: none;
        width: 100%;
        margin-top: 30px;
        margin-bottom: 20px;
      }
    }
    
    @media (max-width: 768px) {
      .cards-container {
        flex-direction: column;
        gap: 20px;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      
      <div className="profile-hero-section" style={{ position: 'relative', minHeight: '100vh' }}>
        
        <div className="shooting-stars">
          {[...Array(50)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(8)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "400px" }}>
            <div className="absolute top-0 w-full h-full bg-center bg-cover"
              style={{ backgroundImage: "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')" }}>
            </div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="relative">
                        <img alt="Jenna Stones" src={require("assets/img/team-2-800x800.jpg").default}
                          className="shadow-xl rounded-full h-auto align-middle border-none absolute -m-16 -ml-20 lg:-ml-16 max-w-150-px" />
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center">
                      <div className="py-6 px-3 mt-32 sm:mt-0 flex gap-2 justify-end">
                        <button className="btn-primary">📧 Contacter</button>
                        <button className="btn-comment" onClick={() => setShowComments(true)}>💬 Commenter</button>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1">
                      <div className="flex justify-center py-4 lg:pt-4 pt-8 gap-4">
                        <div className="p-3 text-center bg-gray-100 rounded-xl">
                          <span className="text-xl font-bold block text-blueGray-600">22</span>
                          <span className="text-sm text-blueGray-400">Friends</span>
                        </div>
                        <div className="p-3 text-center bg-gray-100 rounded-xl">
                          <span className="text-xl font-bold block text-blueGray-600">10</span>
                          <span className="text-sm text-blueGray-400">Photos</span>
                        </div>
                        <div className="p-3 text-center bg-gray-100 rounded-xl">
                          <span className="text-xl font-bold block text-blueGray-600">89</span>
                          <span className="text-sm text-blueGray-400">Comments</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-blueGray-700">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-green-600 font-semibold mt-2">
                        📍 Travaille chez : {currentWorkPlace}
                      </p>
                    )}
                    <div className="text-sm leading-normal mt-2 mb-2 text-blueGray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {workerInfo.location}
                    </div>
                    <div className="mb-2 text-blueGray-600 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-500"></i>
                      {workerInfo.role}
                    </div>
                  </div>
                  
                  <div className="flex flex-wrap">
                    <div className="w-full lg:w-8/12">
                      <div className="cards-container">
                        <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                          <div className="text-6xl mb-4">📄</div>
                          <h3 className="text-xl font-bold text-white mb-2">Mon CV</h3>
                          <p className="text-gray-300 text-sm">Découvrez mon parcours professionnel</p>
                          <div className="mt-4 text-green-400">Cliquez →</div>
                        </div>
                        
                        <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                          <div className="text-6xl mb-4">⭐</div>
                          <h3 className="text-xl font-bold text-white mb-2">Évaluations</h3>
                          <p className="text-gray-300 text-sm">Historique et retours des managers</p>
                          <div className="mt-4 text-green-400">Cliquez →</div>
                        </div>
                      </div>
                    </div>
                    
                    {/* Section commentaires sur la droite */}
                    <div className="w-full lg:w-4/12 lg:pl-6 mt-6 lg:mt-0">
                      <div className="comments-sidebar">
                        <h3 className="text-white font-bold text-lg mb-3 flex items-center gap-2">
                          💬 Commentaires clients
                          <span className="text-xs bg-green-500 text-white px-2 py-1 rounded-full">{comments.length}</span>
                        </h3>
                        
                        {comments.map(comment => (
                          <div key={comment.id} className="comment-item">
                            <div className="flex justify-between items-center">
                              <span className="comment-author">{comment.author}</span>
                              <div className="comment-rating">
                                {[...Array(5)].map((_, i) => (
                                  <span key={i} style={{ color: i < comment.rating ? '#ffc107' : '#555' }}>★</span>
                                ))}
                              </div>
                            </div>
                            <div className="comment-text">{comment.text}</div>
                            <div className="comment-date">{comment.date}</div>
                          </div>
                        ))}
                        
                        <button className="btn-comment" onClick={() => setShowComments(true)}>
                          ✍️ Écrire un commentaire
                        </button>
                      </div>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-blueGray-200 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-blueGray-700 italic">
                          "{workerInfo.bio}"
                        </p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {workerInfo.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* Modal CV */}
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            <div style={{ textAlign: 'center' }}>
              <div className="text-6xl mb-4">👩‍💻</div>
              <h2 className="text-2xl font-bold text-white mb-2">{workerInfo.name}</h2>
              <p className="text-green-400 mb-4">{workerInfo.role}</p>
              <div className="text-left">
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📋 Profil</h3>
                <p className="text-gray-300">{workerInfo.bio}</p>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">💪 Compétences</h3>
                <div className="flex flex-wrap gap-2">
                  {workerInfo.skills.map((skill, i) => (
                    <span key={i} className="skill-tag">{skill}</span>
                  ))}
                </div>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📞 Contact</h3>
                <p className="text-gray-300">📧 {workerInfo.email}</p>
                <p className="text-gray-300">📱 {workerInfo.phone}</p>
                
                <h3 className="text-xl font-bold text-white mt-4 mb-2">🎓 Expérience</h3>
                <p className="text-gray-300">{workerInfo.experience}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal Évaluations */}
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '700px' }}>
            <button onClick={() => setShowManagerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            <div>
              <div className="text-center">
                <div className="text-6xl mb-4">⭐</div>
                <h2 className="text-2xl font-bold text-white mb-2">Gestion des évaluations</h2>
              </div>
              
              <div style={{ background: 'rgba(34,197,94,0.1)', borderRadius: '20px', padding: '20px', marginBottom: '20px' }}>
                <h3 className="text-lg font-bold text-green-400 mb-3">👨‍💼 Panel Manager</h3>
                <div className="mb-3">
                  <p className="text-white">📍 Lieu actuel: {currentWorkPlace || 'Non défini'}</p>
                </div>
                
                <div className="flex gap-3 flex-wrap mb-4">
                  {workerStatus !== 'working' && (
                    <button onClick={activateWorker} className="btn-primary">✅ Activer</button>
                  )}
                  {workerStatus === 'working' && (
                    <button onClick={deactivateWorker} className="btn-danger">🚫 Terminer</button>
                  )}
                </div>
                
                {showPlaceSelector && (
                  <div className="place-selector">
                    <h4 className="text-white text-center col-span-full">Choisir un lieu:</h4>
                    {availablePlaces.map(place => (
                      <div key={place.id} className="place-option" onClick={() => changeWorkPlace(place)}>
                        <div className="text-2xl">{place.icon}</div>
                        <div className="text-white font-bold">{place.name}</div>
                        <div className="text-gray-400 text-sm">{place.location}</div>
                      </div>
                    ))}
                  </div>
                )}
                
                <div className="mt-3">
                  <label className="text-white text-sm">⭐ Note (1-5)</label>
                  <div className="rating-input">
                    {[1,2,3,4,5].map(star => (
                      <span key={star} className={`rating-star ${currentRating >= star ? 'active' : ''}`}
                        onClick={() => setCurrentRating(star)}>★</span>
                    ))}
                  </div>
                </div>
                <div className="mt-3">
                  <label className="text-white text-sm">💬 Commentaire</label>
                  <textarea className="w-full p-2 rounded-lg mt-1 bg-white/10 text-white" rows="3"
                    value={managerComment} onChange={(e) => setManagerComment(e.target.value)}
                    placeholder="Écrivez votre commentaire..."></textarea>
                </div>
                <button onClick={addManagerReview} className="btn-primary w-full mt-3">
                  ✅ Ajouter
                </button>
              </div>
              
              <h3 className="text-lg font-bold text-white mb-3">📋 Historique</h3>
              {workHistory.map((work, index) => (
                <div key={index} className="work-history-item">
                  <div className="flex justify-between items-center flex-wrap">
                    <h4 className="text-white font-bold">{work.place}</h4>
                    <div className="stars">
                      {[...Array(5)].map((_, i) => (
                        <span key={i} style={{ color: i < work.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>
                      ))}
                    </div>
                  </div>
                  <p className="text-gray-300 text-sm">{work.role} • {work.duration}</p>
                  <p className="text-gray-400 text-sm mt-2">"{work.review}"</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      {/* Modal pour ajouter un commentaire */}
      {showComments && (
        <div className="modal-overlay" onClick={() => setShowComments(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowComments(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '24px', cursor: 'pointer' }}>✕</button>
            <div>
              <div className="text-center">
                <div className="text-6xl mb-4">💬</div>
                <h2 className="text-2xl font-bold text-white mb-2">Laisser un commentaire</h2>
                <p className="text-gray-400 text-sm">Partagez votre expérience</p>
              </div>
              
              <div className="mt-4">
                <label className="text-white text-sm block mb-2">👤 Votre nom</label>
                <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30 focus:outline-none focus:border-green-500"
                  value={newComment.author} onChange={(e) => setNewComment({...newComment, author: e.target.value})}
                  placeholder="Entrez votre nom" />
              </div>
              
              <div className="mt-3">
                <label className="text-white text-sm block mb-2">⭐ Note (1-5)</label>
                <div className="rating-input">
                  {[1,2,3,4,5].map(star => (
                    <span key={star} className={`rating-star ${newComment.rating >= star ? 'active' : ''}`}
                      onClick={() => setNewComment({...newComment, rating: star})}>★</span>
                  ))}
                </div>
              </div>
              
              <div className="mt-3">
                <label className="text-white text-sm block mb-2">💬 Votre commentaire</label>
                <textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30 focus:outline-none focus:border-green-500" rows="4"
                  value={newComment.text} onChange={(e) => setNewComment({...newComment, text: e.target.value})}
                  placeholder="Écrivez votre commentaire ici..."></textarea>
              </div>
              
              <button onClick={addComment} className="btn-primary w-full mt-4">
                📤 Publier le commentaire
              </button>
            </div>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
